rules.pseudocode:
for each action a in available_actions:
  if a == 'eat' and food_at_position:
    Q_Pav[a] = mu * h_t * V.get((x, y), 0.0)
  elif a == 'eat' and not food_at_position:
    Q_Pav[a] = -1e9  # unavailable
  elif a == 'stay':
    Q_Pav[a] = mu * h_t * V.get((x, y), 0.0)
  elif a is movement to valid cell (x_a, y_a):
    Q_Pav[a] = mu * h_t * V.get((x_a, y_a), 0.0) - c_step
  elif a is movement to invalid cell (out of bounds):
    Q_Pav[a] = -1e9  # unavailable
